-- 三月课程：依赖与自由
-- 9天课程（三月一日 - 三月九日）
-- 主题：依赖、执著、关系、恐惧

-- 1. 添加课程体系
INSERT INTO course_systems (
  id, system_key, title, description, structure_type,
  is_active, is_system_course, teaching_goals, guidance_keywords, display_order
) VALUES (
  gen_random_uuid(),
  'dependency_freedom',
  '依赖与自由',
  '克里希那穆提《生命之书》三月主题：依赖、执著、关系、恐惧。9天深度探索之旅。',
  'daily_sequential',
  true,
  true,
  '通过克里希那穆提的智慧引导学员探索依赖、执著、关系与恐惧的本质。不提供答案，而是引导学员自己发现真相。',
  ARRAY['引导觉察', '苏格拉底提问', '避免说教', '探索依赖', '面对孤独', '理解关系'],
  50
);

-- 2. 获取刚插入的课程体系ID并添加9天课程内容
DO $$
DECLARE
  v_system_id uuid;
BEGIN
  -- 获取刚创建的课程体系ID
  SELECT id INTO v_system_id FROM course_systems WHERE system_key = 'dependency_freedom';

  -- Day 1: 自由的心是谦和的
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 1, '自由的心是谦和的',
    E'你有没有思考过"依赖性"这个问题？如果深入地去思考这件事，你会发现大部分的人都非常孤独。人心大部分是空虚而肤浅的。我们不知道什么是爱。从这种孤独、匮乏和痛苦的状态里，我们产生了执著于家人或财物的反应。……婚姻其实是一种自我防卫、自我逃避的形式。任何一种防卫的形式都会助长依赖性。一个总想依赖的心是不可能自由的。你需要的是自由，你会发现只有自由的心才是谦和的。……真正的学习却是从已知进入未知。',
    E'克里希那穆提在三月的第一天，直指我们人际关系中最隐秘的痛点：**心理依赖**。\n\n**1. 依赖的根源是内在的贫乏与孤独**\n我们通常认为依赖是因为"爱"或者"需要"。但克氏指出，心理上的依赖源于我们内在的**空虚感和孤独感**。因为我们不敢面对自己内心的贫乏，不敢独自面对那个空荡荡的自我，所以我们拼命向外抓取——抓取伴侣、抓取孩子、抓取财产、抓取某种信仰。我们把别人当作填补内心空洞的材料。\n\n**2. 关系变成了一种防御机制**\n由于我们害怕孤独，我们就建立了各种关系作为一种"自我防卫"的堡垒。当我们说"我不能没有你"时，其实是在说"我不能面对没有你的我自己"。\n\n**3. 只有自由的心才能谦和**\n一个充满依赖的心，充满了恐惧和索取。而"自由"，意味着从依赖和防御中解脱出来。当你不再试图从外界抓取任何东西来填补自己，心就不再有负担。这种无所求、无所惧的状态，就是真正的**谦和**。\n\n**总结：今天的教诲邀请我们诚实地面对自己的孤独。不要用关系去掩盖它，而是去深入了解它。**',
    E'**【冥想主题：拥抱内在的空寂，以此获得自由】**\n\n找一个安静的地方，独自安坐。轻轻闭上眼睛。\n\n让我们开始……深呼吸，感受气息充满你的胸腔，然后缓慢地呼出，带走身体的紧张……\n\n将你的注意力转向内心，去觉察你在关系中的一种"牵挂"或"依赖"的感觉。也许是对伴侣的依赖，对孩子的执著，或者是对某个物品、某个身份的抓取。\n\n想象这种依赖像是一根绳索，连接着你和那个对象……你能感觉到那种"抓紧"的力度吗？\n\n问问自己："如果这就切断了，如果这个人和这个东西彻底消失了，我会感觉怎样？"\n\n不要急着回答，去感受那个假设发生时，身体和心里的反应……是不是有一种恐慌？一种失落？一种空荡荡的感觉？……\n\n是的，这就是我们一直试图逃避的东西——内在的空虚和孤独。\n\n现在，我邀请你，不要转身逃跑。这一次，让我们转过身来，面对这个空虚。\n\n看着那个内心的空洞。它就在那里。但这只是因为我们从未给过它光亮。\n\n当你不再试图用外物来填满它时，当你不再用"关系"来作为防御的盾牌时……你会发现，这个所谓的"孤独"，开始发生变化。\n\n在这"一无所有"中，去感受一种从未有过的轻松。既然不需要填补，就不需要向外乞求。\n\n你站在这里，独立，完整。就像一棵树独自站在旷野中，不需要依附另一棵树才能生长。\n\n这就是自由的味道……\n\n安住在这份自由与谦和的寂静中……',
    E'**【练习名称："如果没有它"的自我检视】**\n\n**时机**：当你感到强烈的需要某人（比如急切等待伴侣回信）、某物（比如必须喝咖啡/刷手机才能安心）或某种情绪慰藉时。\n\n**做法**：\n1. **觉察**：对自己说："我现在感到非常需要这个东西/这个人。"\n2. **假设**：在心里问自己："如果我现在得不到它，如果这一刻我必须独自面对自己，这种焦虑背后的感觉是什么？"\n3. **命名**：试着给那个背后的感觉命名。是"无聊"？是"被遗弃感"？是"不安"？是"空虚"？\n4. **共处**：不要立刻去满足那个欲望。试着与其背后的那个感觉共处 **3分钟**。只是看着它，不试图用那个东西来填补它。\n\n**目的**：这个练习能帮助我们从无意识的"自动反应模式"中跳脱出来，训练我们独立面对内在状态的能力。',
    true, now(), now()
  );

  -- Day 2: 我们从不质疑自己的依赖
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 2, '我们从不质疑自己的依赖',
    E'人为什么会有依赖性？我们的心总是在依赖一些信念、修行体系或哲学系统；我们依赖另一个人来指导我们如何行事；我们总想找到一个能带给我们希望和快乐的老师。因此我们追求的只是一种安全感罢了。……我们从不质疑这个问题。我们从不质疑自己为什么会追求特定形式的安全感……在逃避困境的过程里，我们势必会制造出某种形式的依赖性，而它又会变成我们心中的依据。……若不是能全神贯注地去探索这个问题，也许就会发现依赖并不是问题所在——它只是一种逃避更深的实相的方式。',
    E'今天，克氏引导我们从"依赖的表现"深入到"依赖的动因"。\n\n**1. 依赖即是寻找"依据"**\n我们在心理上渴望某种确定性。生活是流动的、无常的，这让我们感到不安。于是，我们寻找"依据"——无论是宗教教条、哲学系统，还是一个看似强大的伴侣或导师。我们依赖的不是那个人或那个教条本身，而是他们提供给我们的**"安全感"**。\n\n**2. 逃避困境的手段**\n克氏指出，依赖本质上是一种**逃避**。当我们遇到难题时，我们不想自己面对，不想独自承受那份焦虑，于是我们立刻转向他人："告诉我该怎么办？"这种转向他人的动作，就是依赖。\n\n**3. 质疑依赖的根源**\n真正的转化始于"质疑"。不是质疑那个被你依赖的人，而是质疑你自己："为什么我如此渴望安全感？为什么我不敢独自面对当下的困境？"当你开始这样质疑时，你会发现，依赖并不是问题的核心，**你内心那个因恐惧而颤抖的自我**，才是问题的核心。\n\n**总结：今天的功课是"撤回投射"。停止向外寻找依靠，转而向内审视那个乞求依靠的自己。**',
    E'**【冥想主题：抽走心理的拐杖】**\n\n请找到一个安静、私密的空间。坐在椅子上或地板上，保持脊柱挺直。闭上眼睛，双手自然放在膝盖上。\n\n深呼吸……吸气时，感受脊柱的延伸……呼气时，感受臀部稳稳地坐在椅子上。让自己像一座山一样，稳固，安在。\n\n现在，让我们诚实地看进自己的内心。在你的生活中，谁是你的"拐杖"？什么是你的"避风港"？\n\n也许是一个人，你的伴侣、父母或导师……\n也许是一个信念，一种宗教，或者是一个"未来会更好"的希望……\n\n在你的脑海中，把这个依赖的对象具象化。想象它就像一根巨大的、坚固的柱子，立在你的身边。\n你正斜靠在它身上。你把身体的大部分重量都卸在它身上。\n\n现在，我们要进行一个勇敢的实验。\n我邀请你，在深呼吸中，慢慢地……试着让你的身体离开这根柱子。\n把你的重量，从它身上收回来。收回到你自己的脊柱上。\n\n当你刚刚离开那根柱子时，你感觉到了什么？\n是不是有一种摇晃感？一种恐慌？\n\n试着独自站立在虚空之中。没有依靠，没有保证，没有抓手。\n只有你，和你的呼吸。\n你会发现，你并没有倒下。\n\n你不需要外在的拐杖来证明你的存在。你本身就是完整的。\n记住这种感觉。这是自由的滋味。',
    E'**【练习名称：微小的独立时刻】**\n\n**时机**：当你遇到一个小困难、小纠结，或者感到无聊、情绪低落时。通常这时我们的本能反应是：找人倾诉、发消息问意见、或者刷手机寻求慰藉。\n\n**行动**：**推迟依赖行为 15 分钟**。\n\n**做法**：\n1. **拦截冲动**：当你想拿起电话问伴侣"我该穿哪件衣服？"或者"今天发生了件烦心事"时，停住。\n2. **自我对话**：对自己说："我给自己15分钟，先独自面对这个问题/情绪。"\n3. **独自解决/消化**：\n   - 如果是问题，试着自己分析利弊，自己做决定。告诉自己："即使选错了，我也能承担。"\n   - 如果是情绪，试着自己通过书写、散步或深呼吸来消化它。\n4. **事后观察**：15分钟后，如果你还想找人，可以找。但通常你会发现，那种迫切的"依赖感"已经减弱了。\n\n**目的**：锻炼我们的"心理肌肉"，让我们逐步体验到：其实我有能力独自处理很多事。',
    true, now(), now()
  );

  -- Day 3: 更深的依赖元素
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 3, '更深的依赖元素',
    E'其实我不认为依赖是个问题，使我们产生依赖的是另一个更深的元素。……这个更深的心理议题到底是什么？是不是因为我们的心厌恶、害怕孤独？我们的心知不知道它永远在躲避这种状态？只要心不能彻底了解、感受、穿透和解决这份孤独感，依赖便是无法避免的事……',
    E'今天，克里希那穆提带我们挖掘到了依赖的根基——**对孤独（Loneliness）的恐惧**。\n\n**1. 依赖只是症状，孤独才是病灶**\n我们往往试图"戒除"依赖。克氏指出，这只是在处理症状。只要内心深处的那个"黑洞"还在，你就会不可避免地去抓取新的东西来填补。那个黑洞，就是"孤独感"。\n\n**2. 逃避孤独的机制**\n我们的生活，几乎都在围绕着"逃避孤独"而运转。我们工作、社交、娱乐、恋爱、结婚，很多时候都是为了**不要让自己面对那个可怕的空虚时刻**。\n\n**3. 穿透孤独，而非掩盖它**\n克氏给出的解药是革命性的：**不要逃**。当孤独袭来时，不要打开电视，不要打电话。停下来，转身，直接面对它，看着它，甚至进入它。当你完全接受它，孤独就会转化。它会从一种匮乏的痛，转化为一种圆满的"空"——即**寂然独立 (Aloneness)**。前者是乞丐，后者是国王。\n\n**总结：今天的教导是关于勇气的。它要求我们停止逃跑，站住脚跟，去拥抱内心那个最令我们害怕的空洞。**',
    E'**【冥想主题：黑暗房间里的炼金术】**\n\n最好在黄昏或晚上进行。关掉房间的灯，让自己处于一种相对昏暗、安静的环境中。安坐，闭眼。\n\n坐在这个安静的黑暗中。感觉你的身体被黑暗温柔地包裹着。\n\n现在，去触碰你内心深处那个叫做"孤独"的地方。\n它可能感觉像胸口的一个空洞……或者腹部的一种紧缩……\n通常，我们一碰到它就会像触电一样弹开。\n但今天，你是安全的。你有足够的勇气，留在这里。\n\n想象你走进了一个漆黑的空房间。这个房间就是你的"孤独"。\n里面什么都没有。没有家具，没有声音，没有人影。\n只有无边无际的空。\n\n不要试图在这个房间里开灯。不要试图装修它。\n只是走进去，坐在房间的中央。\n感受那份寂静。感受那份空旷。\n\n当你不再抗拒这份孤独，当你不再想逃离这个房间时……奇迹会发生。\n这份"空"，真的可怕吗？\n还是说，它其实是一种无限的宁静？\n\n在这个黑暗的房间里，孤独开始发生转化。\n它不再是一种"被遗弃"的痛苦，而变成了一种"独自存在"的圆满。\n就像深山里的一朵花，独自开放，不为谁开，也不为谁落。\n\n在这份"单独"中，你拥有了一切。因为你不再缺失，你不再乞求。\n你终于回家了。回到了这个只属于你自己的、神圣的中心。',
    E'**【练习名称：十分钟的"绝对空白"】**\n\n**时机**：每天回家后，或者睡前。\n\n**行动**：给自己设定 **10分钟** 的闹钟。\n\n**做法**：\n1. **切断输入**：关掉手机、电视、电脑、音乐。合上书本。\n2. **切断输出**：不与人交谈，不写字，不工作。\n3. **只是坐着**：你可以坐在沙发上，也可以看着窗外。\n4. **观察"想逃"的冲动**：在这10分钟里，你极有可能会感到无聊、焦虑、手足无措，想伸手去拿手机。\n5. **关键动作**：**看着那只手，缩回来。** 看着那个"想做点什么来填补时间"的冲动，不满足它。\n6. **体验**：就让自己在这个"无事可做"的空虚里"熬"过这10分钟。去品尝那个焦躁的味道。\n\n**目的**：这是对"面对孤独"的脱敏疗法。通过每天小剂量的练习，我们逐渐提高对"内在空虚"的耐受力。',
    true, now(), now()
  );

  -- Day 4: 深入地觉知
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 4, '深入地觉知',
    E'依赖性会造成执著和疏离的态度，心会不断地产生冲突……你必须觉察这整个执著和依赖的过程，在不拣择不批判的情况下去觉知它……若是能深入地觉知，有意识地去理解依赖性的完整意义……然后潜意识底端所埋藏的动机、意图和欲求，自然会投射到表层意识。……若是能来来回回地觉察这些潜意识里的投射……你已经发展出一种不间断的觉知，凭着它就能温柔而轻松地整合身心。',
    E'在理解了依赖的根源之后，今天克氏给了我们具体的操作方法：**无拣择的、深入的觉知**。\n\n**1. 不拣择、不批判**\n这是克氏冥想的核心。当我们发现自己依赖别人时，通常的第一反应是自我批判："我太软弱了，我不该这样！"克氏指出，这些反应都是阻碍。批判会制造冲突，压抑会制造反弹。真正的觉知，是像照镜子一样，如实地看着那个"依赖"的样子，不说是好是坏，只是看清它的原貌。\n\n**2. 意识与潜意识的沟通**\n依赖往往根植于潜意识。光靠头脑的分析是无法解决的。克氏提出了一种"深入的觉知"——当你的表层意识足够安静、不带评判时，潜意识里的那些秘密、恐惧和动机，就会像水底的气泡一样，自然地浮到水面上来。\n\n**3. 温柔的整合**\n当我们能"来来回回地觉察"——既看到表面的依赖行为，也看到底下潜伏的恐惧和动机——身心就会发生一种自然的整合。当你看清了毒药是毒药，你自然就会放下它，不需要费力。\n\n**总结：做一个温柔的观察者。不要与你的依赖开战，而是去认识它、了解它、看透它。在全然的了解中，束缚自然解开。**',
    E'**【冥想主题：意识之河的垂钓者】**\n\n安坐。身体放松。将这一刻视为对自己内心世界的一次温柔探访。\n\n调整好你的呼吸……让心慢慢静下来，像一池被搅动的水，慢慢沉淀，变得清澈。\n\n现在，把"依赖"这个主题带入你的意识。不要把它当成一个问题去解决，而是把它当成一部电影去观看。\n\n回想最近一次你感到强烈依赖、嫉妒或不安的时刻。\n看着那个画面。你说了什么？做了什么？\n注意，**不要批判那个自己**。不要说"我不该那样"。\n就像在看别人的故事一样，只是看着。\n\n现在，试着往深处看一点。\n在那一刻的行为之下，你的身体是什么感觉？是紧绷的？是空虚的？\n在那一刻的情绪之下，隐藏着什么念头？\n\n保持安静，给潜意识一点空间。不要急着找答案。\n只是在这份觉知中等待。\n也许，会有一些更早期的画面浮现……童年的某个时刻……某种熟悉的被遗弃感……\n如果它们浮现了，欢迎它们。看着它们。\n\n你看，这一切都是一个连贯的链条：过去的恐惧 -> 现在的焦虑 -> 抓取依赖的行为。\n当你完整地看见这个链条时，你就在这一刻切断了自动化的反应。\n\n就在这份温柔的、不加批判的注视中，让那些紧抓的手，慢慢松开……',
    E'**【练习名称：慢镜头的回放】**\n\n**时机**：当你刚刚经历了一次"依赖发作"之后（例如：因为伴侣没接电话而夺命连环call）。\n\n**行动**：事后进行一次**"无批判复盘"**。\n\n**做法**：\n1. **找个安静的时刻**（比如晚上洗澡时或睡前）。\n2. **回放**：在脑海中像放电影一样，从头到尾回放那件事。\n3. **开启"观察者"视角**：想象你正站在旁边看着当时的自己。\n4. **关键提问**：\n   - "在那一刻，''我''真的想要的是什么？"（是爱？是确认？是安全？）\n   - "那个''想要''背后的恐惧是什么？"（是怕被抛弃？怕自己不够好？）\n5. **自我宽恕**：看完之后，对自己说："我看见了那个受伤的小孩在求救。我理解他的恐惧，但我现在是成年的观察者，我可以给他安全，而不需要向外抓取。"\n\n**目的**：将无意识的冲动转化为有意识的觉察。经过多次练习，这种觉察的速度会越来越快，最终能够在依赖发生的"当下"就产生觉知。',
    true, now(), now()
  );

  -- Day 5: 关系不是一种交易
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 5, '关系不是一种交易',
    E'奠基于需求的互动关系只会带来冲突。我们通常会利用相互依赖的关系来满足自己。心里只要带着目的，真实的关系就不存在了，你可能会利用我，我也会利用你。在这种情况下，我们就失去了真正的联结。……社会就是你和他人关系的一种投射。如果利用他人来满足你的需求，就不可能和那个人建立起真正的联结了。为了自己的舒适和方便，你把另一个人当成家具来用，在这种情况下，你和他怎么可能建立起真正的关系呢？',
    E'这一天的教诲像手术刀一样精准地剖开了我们所谓"亲密关系"的假象。克氏指出，大部分人际关系，本质上是一种**相互利用的商业交易**。\n\n**1. 把人当成"家具"**\n这是一个非常形象且刺痛的比喻。我们买家具是为了让自己坐得舒服。同样，我们建立关系，往往是为了让自己心理上"舒服"——我们需要有人倾听、有人陪伴、有人养家、有人让我们有面子。当我们基于"功能"和"需求"去对待一个人时，我们只看到了他对我们的**用途**。\n\n**2. 利用即是冲突的根源**\n只要存在"利用"，就必然存在冲突。当那个被你当作"舒适来源"的人，突然不再让你舒适时，你就会愤怒、失望。这种愤怒暴露了真相：你爱的不是他，你爱的是他给你提供的服务。\n\n**3. 真正的联结始于"无求"**\n如果我不再想从你身上得到什么——不求安全感，不求快乐，不求排解孤独——那我为什么还要和你在一起？克氏说，只有在那个时候，真正的**"联结"**才发生。那时，我是作为一个完整的生命与你相遇，而不是作为一个乞丐向你讨饭。\n\n**总结：检视我们在关系中的"功利心"。学会把对方从"工具人"还原为"人"，停止剥削，开始真正的相遇。**',
    E'**【冥想主题：放下需求，看见"他者"】**\n\n安坐。在心中邀请一位你非常亲密的人（伴侣、孩子或挚友）来到你的意识空间。\n\n深呼吸……让心静下来。\n现在，在你的脑海中，清晰地浮现出那个对你很重要的人的脸庞。\n看着他/她。\n\n诚实地问自己："我在这段关系中，想要得到什么？"\n不要急着否认。看看内心深处。\n我是不是希望他给我安全感？\n我是不是希望他听我说话，理解我？\n我是不是希望他能让我感到自己有价值？\n看着这些"需求"，它们就像一根根吸管，插在对方身上，吸取着能量。\n\n现在，想象一下，如果把这些吸管都拔掉……\n如果我不要求他给我安全感……\n如果我不要求他必须理解我……\n如果我对他**一无所求**……\n\n当这些需求消失时，看着眼前这个脑海中的人。\n你是不是第一次，看到了一个独立的生命？\n他有他自己的恐惧，他自己的渴望，他自己的命运。他不是为了满足你而存在的。\n\n试着在心里对他鞠一躬，说："对不起，我曾把你当作满足我需求的工具。"\n"现在，我愿意放下这些需求。"\n"我愿意看着原本的你。"\n\n感受一下，当你放下"索取"的念头时，心是不是变得宽广了？\n一种不一样的温情开始流动。这不是基于"我需要你"的抓取，而是基于"我看见你"的慈悲。',
    E'**【练习名称："如果不……我还爱吗？"】**\n\n**时机**：当你对亲密的人感到失望、不满或生气时。\n\n**行动**：**反向提问**。\n\n**做法**：\n1. **觉察不满**：比如，你生气是因为丈夫没有做家务，或者孩子考试没考好。\n2. **识别需求**：问自己"我为什么生气？"——"因为我需要他帮我分担（工具需求）"或"因为我需要他优秀来证明我是好父母（面子需求）"。\n3. **终极提问**：看着对方，在心里问自己："如果他**永远**都学不会做家务，我还能爱这个生命吗？""如果他**永远**平凡，我还能接纳这个孩子吗？"\n4. **观察**：这个问题会瞬间让你看到，你的爱中夹杂了多少"交易"的成分。不要求你立刻变得无私，只要**看见**这个交易，你的怒气就会平息一半，智慧就会生起。',
    true, now(), now()
  );

  -- Day 6: "我"的占有欲
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 6, '"我"的占有欲',
    E'弃绝世俗或自我牺牲并不是值得被赞美和仿效的伟大精神。我们总想占有一些东西，因为缺少了这些东西，我们就什么也不是了。……"我"因为恐惧自己不存在，所以总是执著于名望、家具或某种价值观。……被占有的东西如果无法满足我们或带来了痛苦，我们就会放弃它而去追求更令人愉悦的东西。……只要不甘愿做个什么都不是的人，不可避免地一定会助长痛苦和敌意。',
    E'今天，克氏探讨了"自我"与"占有"的关系。他指出，**"我"并不是一个独立的实体，"我"就是我所占有的东西的总和**。\n\n**1. 占有即存在**\n我们为什么如此执著于占有？不仅仅是物质（房子、车子），还有非物质的（名声、知识、美德、信仰）。克氏说，这是因为如果我们不占有这些，我们就感到自己"什么都不是"。试着把你的名字、职业、财产、家庭、记忆、信仰统统拿走，还剩下什么？那种空无一物的感觉让我们恐惧。\n\n**2. "我"就是占有物**\n这不是说"我"拥有房子，而是说"我"**变成了**房子，"我"**变成了**那个头衔。当房子受损或头衔被辱时，我们觉得是"我"受损了。所谓的"个性"或"自我"，其实就是一堆占有物的堆砌。\n\n**3. 甘愿什么都不是**\n真正的自由，不是形式上的"弃绝世俗"（那往往只是另一种形式的自我炫耀）。真正的解脱是**内心深处对于"什么都不是"的彻底接纳**。当你不再需要用任何东西来装饰自己、证明自己时，恐惧就消失了。在那份空无中，才有真正的实相。\n\n**总结：不要通过"拥有"来寻找自己。只要你还想"成为"什么，你就还在恐惧的牢笼里。只有当你敢于"什么都不是"，你才拥抱了整个宇宙。**',
    E'**【冥想主题：剥洋葱式的自我消融】**\n\n安坐。想象自己像一棵洋葱，包裹着层层的外皮。\n\n坐直，闭上眼。让我们来看看，这个我们如此维护的"我"，到底是由什么构成的。\n\n想象"我"是一层层包裹起来的。现在，我们开始剥离。\n\n第一层，是你的**物质占有**。你的房子，车子，衣服，银行存款。\n想象一场大火，让它们瞬间化为乌有。\n看着它们消失。你还在吗？是的，那个觉知的你还在。但那个"富有的你"消失了。\n\n第二层，是你的**社会身份**。你的职位，头衔，学历，作为父母或子女的角色。\n想象到了一个没人认识你的荒岛。这些头衔都失去了意义。\n剥掉这一层。你不再是经理，不再是博士。你只是一个生命。\n\n第三层，是你的**身体形象**。你的美貌，健康，年龄。\n想象岁月的流逝，这些都在衰退，消失。\n剥掉对身体的认同。你不是这个驱壳。\n\n第四层，最难的一层，是你的**内在占有**。你的知识，你的经验，你的性格，你的信仰，你的美德。\n试着把这些也放下。忘掉你读过的书，忘掉你的过去。\n把"我是个好人"、"我是个聪明人"的标签也撕掉。\n\n现在，还剩下什么？\n没有名字，没有身份，没有财产，没有过去。\n这里只有一片虚空。一种"什么都不是"的状态。\n\n在这个状态里待一会儿。\n穿过恐惧，去感受那份轻盈。\n因为什么都不是，所以什么都无法伤害你。\n你变成了浩瀚的虚空本身。',
    E'**【练习名称：我是谁？（否定法）】**\n\n**时机**：当你因为失去某样东西而难过，或因为得到某样东西而沾沾自喜时。\n\n**行动**：进行一次**身份切割**。\n\n**做法**：\n1. **得到时**：比如你被升职了，被人夸奖了。在心里告诉自己："这只是一个发生，**这不是我**。不要把它贴在身上。"\n2. **失去时**：比如丢了钱，或者被人误解了。在心里告诉自己："这是身外之物的损失，**这不是我**。我的本质并没有因此减少一分一毫。"\n3. **日常提醒**：看着镜子里的自己，指着那些外在的特征（发型、衣服），对自己说："这不是我。这只是我暂时使用的工具。"',
    true, now(), now()
  );

  -- Day 7: 剥削者即是被剥削的人
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 7, '剥削者即是被剥削的人',
    E'大部分的人都喜欢剥削以及被剥削……其实剥削和被剥削是同一回事。利用别人来满足自己往往会助长依赖性，而且当你依赖某个对象时，就会想去占有它……若是没有任何可以依赖的对象，譬如财物、人或观念，你整个人就空了……然而你总想变成某个东西，为了避免让自己变得什么都不是，所以才渴望加入这个组织或那个组织……如此一来，你就变成了被剥削的人，反过来你也成了剥削者。',
    E'今天，克氏将视角拓展到了社会和精神组织的层面，揭示了**"权威与追随"**背后的心理机制。\n\n**1. 剥削的双向性**\n我们通常认为剥削是单向的。但克氏指出，这是一个双向合谋的过程。当你为了寻求安全感、心灵慰藉或某种地位而加入一个组织、追随一位大师时，你在**利用**这个组织或大师来填补你的空虚。这就是你在剥削他们。而为了维持这种慰藉，你心甘情愿地交出你的自由，这就让你成了被剥削者。\n\n**2. 对"空无"的恐惧驱动了盲从**\n为什么我们热衷于各种团体、党派、宗教？因为如果把这些标签撕掉，我们就要独自面对内在的贫乏。我们害怕成为"局外人"，害怕独自一人的寒冷。所以我们抱团取暖。我们把自我交出去，换取一个"归属感"。\n\n**3. 成为自己的光**\n真正的自由意味着不再从任何外在的权威、组织或体系中寻求确认。你不利用它们来壮胆，它们也就无法剥削你。你必须敢于做一个心理上的"无国籍者"、"无教派者"。只有这样，你才能成为一个真正独立、清醒的人。\n\n**总结：反思我们的"归属感"。看看我们加入的团体、信奉的教条，是为了寻求真理，还是为了逃避独自面对人生的恐惧？**',
    E'**【冥想主题：切断心理脐带】**\n\n安坐。想象自己置身于一个充满各种声音和指引的市场中。\n\n深呼吸……让你的脊柱挺直，像一根连接天地的天线。\n\n现在，检视一下你的精神世界。\n你是否在依赖某个权威？某位导师？某个团体？或者某种特定的思想体系？\n想象有一根无形的脐带，连接着你和那个权威。\n你通过这根脐带，吸取着安全感、方向感和"我是对的"的优越感。\n只要连着它，你就觉得安全，你是某个伟大计划的一部分。\n\n但是，这根脐带也束缚了你。它让你无法独立行走，无法用自己的眼睛看世界。\n现在，问问自己："我敢剪断它吗？"\n\n试着在观想中，拿起一把名为"独立"的剪刀。\n咔嚓。\n剪断那根向外寻求真理的脐带。\n\n感受一下断开那一瞬间的恐慌……"我该去哪？谁来告诉我答案？"\n看着这份恐慌。不要退缩。\n然后，感受紧接着涌上来的力量。\n你自由了。\n你不再是信徒，不再是追随者，不再是某个组织的一员。\n你是你自己。\n真理不在那个权威手里，真理就在你当下的生命里。\n\n看着你脚下的路。虽然没有路标，但你手里拿着灯。\n你自己就是那盏灯。',
    E'**【练习名称：权威祛魅】**\n\n**时机**：当你听到某位"大人物"、"专家"或"大师"发表观点，而你本能地想要点头盲从时。\n\n**行动**：**暂停并平视**。\n\n**做法**：\n1. **觉察**：注意到自己内心那个"想找个爸爸/权威来依靠"的冲动。\n2. **去光环**：在心里想象这位大人物也是一个普通人。他也会便秘，也会跟家人吵架，也有恐惧和困惑。把神坛上的人拉回地面。\n3. **独立思考**：问自己："抛开他的头衔和光环，这句话本身有道理吗？它符合我的生命经验吗？"\n4. **结论**：不要因为是"他"说的就信，也不要因为是"他"说的就反。只看事实。',
    true, now(), now()
  );

  -- Day 8: 执著就是我们的实相
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 8, '执著就是我们的实相',
    E'世上没有所谓的不执著这个东西，存在的只有执著。我们的心会发明不执著这个东西来对抗执著所产生的痛苦。……你想要逃避执著所带来的痛苦，于是又去找寻另一个东西来对抗它，结果还是落入到执著的活动里。……刻意培养不执著的态度只会让你的心执著于另一种态度。……观察一下自己的心念活动，你会发现一个不凡的真相。',
    E'今天，克氏破解了一个常见的灵性陷阱：**对"不执著"的执著**。\n\n**1. "不执著"是头脑的发明**\n当我们因为执著而痛苦时，我们会告诉自己："我要放下，我要不执著。"克氏指出，这个"我要不执著"的念头，其实是另一种执著。你执著于"不痛苦"的状态，你执著于"成为一个超脱的人"的理想。这只是从一个监狱跳到了另一个监狱。\n\n**2. 对抗即是延续**\n当你努力去"戒除"执著时，你其实是在和执著打仗。这场战争反而赋予了执著能量，让它变得更顽固。就像你拼命告诉自己"不要想大象"，你满脑子都会是大象。\n\n**3. 只是观察"执著"本身**\n真正的解脱之道，不是去追求"不执著"，而是**如实地去了解"执著"**。当执著升起时，不要说"这不好，我要改"。而是像科学家观察昆虫一样看着它："哇，看这个执著，它是怎么运作的？它给我带来了什么感觉？"\n当你全然地、不带评判地看着执著时，你会看到它的荒谬和虚妄。在那一刻，执著会像秋天的叶子一样，自然脱落。不是你把它**拔**下来的，是它自己**掉**下来的。\n\n**总结：不要试图成为"高僧"，承认你就是个凡人，承认你现在很执著。与其追求虚假的"放下"，不如诚实地拥抱你当下的"抓取"，看透它，直到它自然消融。**',
    E'**【冥想主题：像看电影一样看执著】**\n\n安坐。让心静下来。\n\n现在，让我们做一个实验。不要试图去"冥想"，也不要试图变得"平静"。我们只是来观察。\n\n把一件你非常执著的事情带到眼前。也许是一个必须得到的结果，也许是一个让你放不下的人。\n看着这份执著。感觉一下它那种"黏糊糊"的、抓紧的能量。\n\n通常，我们会对自己说："哎呀，我太执著了，我要放下。"\n今天，别这么做。\n相反，承认它。对自己说："是的，我现在非常执著。这就是我的现状。"\n\n允许这份执著存在。不要赶它走。\n像看显微镜下的标本一样看它。\n问它："你在保护什么？"\n"你为什么这么害怕失去？"\n\n当你这样看着它时，你会发现，你和它之间产生了一点距离。\n你不再是"那个执著的人"，你变成了"看着执著的觉知"。\n在这个觉知里，没有挣扎，没有"我必须放下"的焦虑。\n\n只有"看"。\n就在这纯粹的"看"之中，那个紧抓的拳头，是不是稍微松动了一点点？\n不是因为你用力掰开的，而是因为它被光照亮了，它自己忘记了用力。\n\n这就是秘密。不要努力去不执著。\n只是看着执著，直到看懂它。\n懂了，就放下了。',
    E'**【练习名称：给"执著"配音】**\n\n**时机**：当你发现自己对某件事特别较劲、放不下、反复纠结时。\n\n**行动**：**幽默化观察**。\n\n**做法**：\n1. **识别**：意识到"啊，执著模式启动了。"\n2. **拟人化**：想象这个执著是一个滑稽的小丑，或者一个撒泼打滚的小孩。\n3. **配音**：在心里给它配个音。比如用那种夸张的卡通声音说："我不依我不依！我就要这个！没有这个我就活不下去了！"\n4. **效果**：当你能带着幽默感去看待那个抓狂的"自我"时，你就已经从执著中抽离出来了。你会对此会心一笑，那个能量的结就松开了。',
    true, now(), now()
  );

  -- Day 9: 执著就是自我欺骗
  INSERT INTO course_contents (
    system_id, content_type, sequence_number, title,
    original_text, deep_interpretation, meditation_guide, life_practice,
    is_published, created_at, updated_at
  ) VALUES (
    v_system_id, 'daily_lesson', 9, '执著就是自我欺骗',
    E'我们和我们所占有的东西是同一回事。只要有执著就不可能有高尚的精神。执著于知识跟其他的上瘾倾向是没有差别的。……执著就是一种自我耽溺或自我欺骗……其目的是要逃避自我空虚感。我们所执著的财物、人或观念变得越来越重要，因为缺少了这些东西，自我就什么也不是了。害怕自己什么都不是，会助长心中的幻觉……若是能放下结论，实相就会出现。',
    E'今天是对前几天内容的总结与升华。克氏再次强调，**执著是填补空虚的自我欺骗**。\n\n**1. 执著即上瘾**\n克氏说"执著于知识跟其他的上瘾倾向没有差别"。我们通常觉得吸毒、酗酒是不好的上瘾，但认为执著于知识、修行、工作是"高尚"的。克氏指出，从心理机制上看，它们完全一样——都是为了**逃避面对当下的空虚**。只要你是为了逃避而抓取，无论抓取的是圣经还是酒瓶，都是自我耽溺。\n\n**2. 结论是智慧的障碍**\n因为害怕不确定性，我们执著于各种"结论"（比如"我是个怎样的人"、"世界是怎样的"）。这些结论给了我们虚假的安全感。但智慧是活的，结论是死的。抓着死的结论不放，我们就无法应对活的生活。放下结论，意味着愿意活在"不知道"的状态里，这才是智慧的开端。\n\n**3. 放下即实相**\n当我们不再用人、物、知识、结论来填满自己时，那个所谓的"我"就瘪了下去。我们可能什么都不是了。但这正是奇迹发生的地方。当虚假的填充物消失，真实的实相才会显露出来。就像只有拨开云雾，才能看见蓝天。\n\n**总结：诚实地检视那些我们自以为"高尚"的执著。看清它们作为"填塞物"的本质，勇敢地让心空出来。**',
    E'**【冥想主题：清空内心的抽屉】**\n\n安坐。深呼吸。\n\n想象你的心是一个抽屉。\n拉开来看看，里面塞满了什么？\n有你的"成就"，有你的"知识"，有你的"委屈"，有你的"计划"，还有你对这个世界的各种"看法"。\n塞得满满当当，连一点缝隙都没有。\n这就是为什么你感到沉重，感到无法呼吸。\n\n现在，让我们来做一次清理。\n拿起那个叫"我的成就"的奖杯，看一看。它给了你安全感，但也给了你压力。\n把它拿出来，放在一边。\n拿起那本叫"我的知识"的书。它让你觉得自己聪明，但也让你产生了傲慢。\n把它拿出来，放在一边。\n拿起那个叫"我的委屈"的包裹。你紧抓着它不放，以为它是你的护身符。\n把它也拿出来。\n\n继续清理……把"我是谁"的定义拿出来……把"未来该怎样"的焦虑拿出来……\n直到这个抽屉变得空空如也。\n\n看着这个空的抽屉。\n它里面什么都没有，只有空间。\n风可以吹过，光可以照进。\n这就是"空心"的状态。\n这就是初学者的心。\n\n在这个空荡荡的状态里，你感到匮乏吗？\n还是感到一种无限的可能性？\n当你不执著于任何东西时，你其实拥有了一切。\n因为你没有了边界。\n\n安住在这份清空的轻盈里。\n如果你发现自己又想抓回什么东西放进去，只要看着那个动作，然后轻轻把手松开。',
    E'**【练习名称：每天扔掉一个"看法"】**\n\n**时机**：当你发现自己对某人或某事产生了一个固定的评判或结论时（比如"他就是个自私的人"、"这种工作毫无意义"）。\n\n**行动**：**主动丢弃**。\n\n**做法**：\n1. **识别结论**：抓住脑子里那个固定的念头。\n2. **质疑它**：问自己："这真的是全部的真相吗？还是我为了省事而贴的标签？"\n3. **扔掉它**：在心里做一个扔垃圾的动作，对自己说："我扔掉这个结论。我愿意重新、新鲜地看待这个人/这件事。"\n4. **留白**：让自己处于一种"我不知道他是怎样的，我正在观察"的开放状态。\n\n**目的**：这个练习帮我们清理心智的淤泥，防止我们被过去的经验和成见所固化，保持心智的鲜活与敏锐。\n\n---\n\n**恭喜你完成了9天的依赖与自由之旅！**\n\n希望这9天的探索，能够帮助你更深入地了解自己，看见那些隐藏在关系、执著背后的恐惧与渴望。记住，真正的自由不在外面，它就在你对自己内心诚实觉察的每一刻。',
    true, now(), now()
  );

END $$;
